import{_ as n,C as s,o as a,c as i,a3 as o,b as d,w as r,a as l,E as c,a4 as p}from"./chunks/framework.aYYe0dfI.js";const k=JSON.parse('{"title":"Module generate:analysis","description":"The generate:analysis module is responsible for transforming raw language model outputs into structured symbol analyses—covering functions, types, variables, and declarations—that drive documentation generation. It owns all logic for parsing, normalizing, merging, and applying analyses: it constructs analysis prompts for individual symbols, interprets free‑form or structured model responses (via parse_structured_response and parse_markdown_prompt_output), applies fallback analyses when primary results are unavailable, and normalizes Markdown fragments for consistent downstream processing.","frontmatter":{"title":"Module generate:analysis","description":"The generate:analysis module is responsible for transforming raw language model outputs into structured symbol analyses—covering functions, types, variables, and declarations—that drive documentation generation. It owns all logic for parsing, normalizing, merging, and applying analyses: it constructs analysis prompts for individual symbols, interprets free‑form or structured model responses (via parse_structured_response and parse_markdown_prompt_output), applies fallback analyses when primary results are unavailable, and normalizes Markdown fragments for consistent downstream processing.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/modules/generate/analysis.md","filePath":"en/clore/modules/generate/analysis.md"}'),m={name:"clore/modules/generate/analysis.md"};function u(h,e,f,y,g,b){const t=s("Mermaid");return a(),i("div",null,[e[1]||(e[1]=o('<h1 id="module-generate-analysis" tabindex="-1">Module <code>generate:analysis</code> <a class="header-anchor" href="#module-generate-analysis" aria-label="Permalink to &quot;Module `generate:analysis`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The <code>generate:analysis</code> module is responsible for transforming raw language model outputs into structured symbol analyses—covering functions, types, variables, and declarations—that drive documentation generation. It owns all logic for parsing, normalizing, merging, and applying analyses: it constructs analysis prompts for individual symbols, interprets free‑form or structured model responses (via <code>parse_structured_response</code> and <code>parse_markdown_prompt_output</code>), applies fallback analyses when primary results are unavailable, and normalizes Markdown fragments for consistent downstream processing.</p><p>The public implementation scope includes functions such as <code>build_symbol_analysis_prompt</code>, <code>apply_symbol_analysis_response</code>, <code>store_fallback_analysis</code>, <code>normalize_markdown_fragment</code>, <code>parse_structured_response</code>, <code>parse_markdown_prompt_output</code>, and the predicate helpers <code>analysis_prompt_kind_for_symbol</code>, <code>symbol_prompt_kinds_for_symbol</code>, <code>is_declaration_summary_prompt</code>, and <code>is_base_symbol_analysis_prompt</code>. These entry points integrate with the broader generation pipeline by accepting lightweight integer handles for symbols, models, and contexts, and returning integer codes or handle results that indicate success, error conditions, or which prompt kinds apply. The module also provides internal fallback and lenient parsing routines for each analysis category (function, type, variable) and merges partial analyses into a coherent whole.</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./../config/"><code>config</code></a></li><li><a href="./../extract/"><code>extract</code></a></li><li><a href="./evidence"><code>generate:evidence</code></a></li><li><a href="./markdown"><code>generate:markdown</code></a></li><li><a href="./model"><code>generate:model</code></a></li><li><code>std</code></li><li><a href="./../support/"><code>support</code></a></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./dryrun"><code>generate:dryrun</code></a></li><li><a href="./scheduler"><code>generate:scheduler</code></a></li></ul><h2 id="dependency-diagram" tabindex="-1">Dependency Diagram <a class="header-anchor" href="#dependency-diagram" aria-label="Permalink to &quot;Dependency Diagram&quot;">​</a></h2>',9)),(a(),d(p,null,{default:r(()=>[c(t,{id:"mermaid-70",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20M0%5B%22generate%22%5D%0A%20%20%20%20I0%5B%22config%22%5D%0A%20%20%20%20I0%20--%3E%20M0%0A%20%20%20%20I1%5B%22extract%22%5D%0A%20%20%20%20I1%20--%3E%20M0%0A%20%20%20%20I2%5B%22support%22%5D%0A%20%20%20%20I2%20--%3E%20M0%0A"})]),fallback:r(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o('<h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-generate-analysis-prompt-kind-for-symbol" tabindex="-1"><code>clore::generate::analysis_prompt_kind_for_symbol</code> <a class="header-anchor" href="#clore-generate-analysis-prompt-kind-for-symbol" aria-label="Permalink to &quot;`clore::generate::analysis_prompt_kind_for_symbol`&quot;">​</a></h3><p>Declaration: <code>generate/analysis.cppm:27</code></p><p>Definition: <code>generate/analysis.cppm:286</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function <code>clore::generate::analysis_prompt_kind_for_symbol</code> uses a straightforward sequence of conditional checks on the symbol kind to determine which category of analysis prompt is appropriate. It first verifies whether the kind corresponds to a function via <code>clore::generate::is_function_kind</code>, then a type via <code>clore::generate::is_type_kind</code>, and finally a variable via <code>clore::generate::is_variable_kind</code>. On the first match, it returns the corresponding enumerator of <code>PromptKind</code> (respectively <code>PromptKind::FunctionAnalysis</code>, <code>PromptKind::TypeAnalysis</code>, or <code>PromptKind::VariableAnalysis</code>). If none of the conditions hold, the function returns <code>std::nullopt</code>, indicating that no analysis prompt kind is applicable. The control flow is purely linear, with no loops or branching beyond the early-return pattern. Its only dependencies are the helper predicates for symbol kind classification and the <code>PromptKind</code> enum type.</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>sym.kind</code></li><li><code>PromptKind::FunctionAnalysis</code></li><li><code>PromptKind::TypeAnalysis</code></li><li><code>PromptKind::VariableAnalysis</code></li><li><code>std::nullopt</code></li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to determine which analysis prompt kind to generate for a symbol</li><li>Called during page building to select analysis prompt template</li></ul><h3 id="clore-generate-apply-symbol-analysis-response" tabindex="-1"><code>clore::generate::apply_symbol_analysis_response</code> <a class="header-anchor" href="#clore-generate-apply-symbol-analysis-response" aria-label="Permalink to &quot;`clore::generate::apply_symbol_analysis_response`&quot;">​</a></h3><p>Declaration: <code>generate/analysis.cppm:39</code></p><p>Definition: <code>generate/analysis.cppm:348</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function <code>clore::generate::apply_symbol_analysis_response</code> first computes a <code>target_key</code> from the symbol <code>sym</code> via <code>make_symbol_target_key</code>. It then dispatches on the <code>kind</code> parameter inside a <code>switch</code> statement. For each recognized <code>PromptKind</code>, it attempts to parse the <code>raw_response</code> using the appropriate lenient parser from the anonymous namespace: <code>parse_function_analysis_lenient</code>, <code>parse_markdown_prompt_output</code>, <code>parse_type_analysis_lenient</code>, or <code>parse_variable_analysis_lenient</code>. If parsing fails, a <code>std::unexpected</code> error is returned immediately. For <code>FunctionAnalysis</code> and <code>TypeAnalysis</code> kinds, the function also generates a fallback analysis via <code>fallback_function_analysis</code> or <code>fallback_type_analysis</code>, then merges the parsed result into the store using <code>merge_function_analysis</code> or <code>merge_type_analysis</code>. For declaration/implementation summary kinds (<code>FunctionDeclarationSummary</code>, <code>FunctionImplementationSummary</code>, <code>TypeDeclarationSummary</code>, <code>TypeImplementationSummary</code>), the parsed markdown is assigned to the corresponding <code>overview_markdown</code> or <code>details_markdown</code> field of the analysis in <code>analyses</code>. For <code>VariableAnalysis</code>, the parsed value is assigned directly to <code>analyses.variables[target_key]</code>. The default branch returns an error for unsupported <code>kind</code> values.</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Mutates the <code>SymbolAnalysisStore</code> passed by reference, updating function, type, or variable analysis entries.</li></ul><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>analyses</code> parameter (mutable reference, reads existing analysis maps)</li><li><code>sym</code> parameter (symbol info)</li><li><code>model</code> parameter (project model)</li><li><code>kind</code> parameter (prompt kind)</li><li><code>raw_response</code> parameter (response string)</li><li>Output of <code>make_symbol_target_key(sym)</code></li><li>Output of <code>prompt_request_key(PromptRequest{...})</code></li><li>Internal parsing functions (e.g., <code>parse_function_analysis_lenient</code>, <code>parse_markdown_prompt_output</code>)</li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li><code>analyses.functions[target_key]</code> (function analysis or markdown fields)</li><li><code>analyses.types[target_key]</code> (type analysis or markdown fields)</li><li><code>analyses.variables[target_key]</code> (variable analysis)</li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called to process a symbol analysis response and update the internal analysis store</li><li>Used after receiving a response from a prompt request for a specific symbol and prompt kind</li></ul><h3 id="clore-generate-build-symbol-analysis-prompt" tabindex="-1"><code>clore::generate::build_symbol_analysis_prompt</code> <a class="header-anchor" href="#clore-generate-build-symbol-analysis-prompt" aria-label="Permalink to &quot;`clore::generate::build_symbol_analysis_prompt`&quot;">​</a></h3><p>Declaration: <code>generate/analysis.cppm:46</code></p><p>Definition: <code>generate/analysis.cppm:429</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function <code>clore::generate::build_symbol_analysis_prompt</code> begins with a <code>switch</code> on the <code>kind</code> parameter to dispatch to one of several <code>build_evidence_for_*</code> helper functions, each tailored to a specific <code>PromptKind</code> (e.g., <code>FunctionAnalysis</code>, <code>TypeDeclarationSummary</code>, <code>VariableAnalysis</code>). These helpers populate an <code>EvidencePack</code> object using the provided <code>sym</code>, <code>model</code>, <code>config</code>, and (in some cases) <code>analyses</code>. After the switch, the function sets common fields on the evidence: <code>page_id</code> to the string <code>&quot;symbol_analysis_phase&quot;</code>, <code>prompt_kind</code> to the result of <code>prompt_kind_name(kind)</code>, and <code>subject_name</code> to <code>sym.qualified_name</code>. It then delegates to <code>build_prompt(kind, evidence)</code> to assemble the final prompt string. If <code>build_prompt</code> fails, the error is wrapped into a <code>GenerateError</code> and returned via <code>std::unexpected</code>. The function also returns an error for any <code>kind</code> that does not match the supported cases.</p><p>Dependencies include the <code>build_evidence_for_*</code> family of functions, <code>build_prompt</code>, <code>prompt_kind_name</code>, and <code>make_symbol_target_key</code> (used in error messages). The overall control flow is a linear dispatch–assembly–construction pattern with two distinct failure points: the default switch case and a failed <code>build_prompt</code> call.</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>sym</code></li><li><code>kind</code></li><li><code>model</code></li><li><code>config.project_root</code></li><li><code>analyses</code></li><li><code>prompt_kind_name(kind)</code></li><li><code>sym.qualified_name</code></li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called to build a prompt for a specific symbol analysis kind.</li><li>Used in the documentation generation process to create LLM prompts for symbol analysis.</li></ul><h3 id="clore-generate-is-base-symbol-analysis-prompt" tabindex="-1"><code>clore::generate::is_base_symbol_analysis_prompt</code> <a class="header-anchor" href="#clore-generate-is-base-symbol-analysis-prompt" aria-label="Permalink to &quot;`clore::generate::is_base_symbol_analysis_prompt`&quot;">​</a></h3><p>Declaration: <code>generate/analysis.cppm:31</code></p><p>Definition: <code>generate/analysis.cppm:325</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function implements a membership test by comparing the <code>kind</code> parameter against three prompt-kind enumerators: <code>PromptKind::FunctionAnalysis</code>, <code>PromptKind::TypeAnalysis</code>, and <code>PromptKind::VariableAnalysis</code>. Internally, the control flow reduces to a single boolean expression composed of equality comparisons combined with logical OR. This function serves as a classification predicate that dispatches to a common decision point; its only dependency is the definition of <code>PromptKind</code> and its associated values.</p><h4 id="side-effects-3" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-3" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-3" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-3" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>parameter <code>kind</code> of type <code>PromptKind</code></li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>classifying prompt kinds as base symbol analysis</li><li>filtering in conditional branches</li></ul><h3 id="clore-generate-is-declaration-summary-prompt" tabindex="-1"><code>clore::generate::is_declaration_summary_prompt</code> <a class="header-anchor" href="#clore-generate-is-declaration-summary-prompt" aria-label="Permalink to &quot;`clore::generate::is_declaration_summary_prompt`&quot;">​</a></h3><p>Declaration: <code>generate/analysis.cppm:33</code></p><p>Definition: <code>generate/analysis.cppm:330</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>This function acts as a simple predicate that determines whether a given <code>PromptKind</code> corresponds to either a function or a type declaration summary. Internally, it performs a direct equality check against the two enumerators <code>PromptKind::FunctionDeclarationSummary</code> and <code>PromptKind::TypeDeclarationSummary</code>, returning <code>true</code> if either comparison succeeds and <code>false</code> otherwise. The only dependency is the <code>PromptKind</code> enumeration, which defines the set of prompt kinds used throughout the generation pipeline. The control flow is entirely linear—no branches other than the short‑circuited logical <code>or</code> <code>operator</code>.</p><h4 id="side-effects-4" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-4" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-4" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-4" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>parameter <code>kind</code> of type <code>PromptKind</code></li></ul><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used to filter prompt kinds for declaration summaries</li><li>called to classify a <code>PromptKind</code> as a declaration-related prompt</li></ul><h3 id="clore-generate-normalize-markdown-fragment" tabindex="-1"><code>clore::generate::normalize_markdown_fragment</code> <a class="header-anchor" href="#clore-generate-normalize-markdown-fragment" aria-label="Permalink to &quot;`clore::generate::normalize_markdown_fragment`&quot;">​</a></h3><p>Declaration: <code>generate/analysis.cppm:21</code></p><p>Definition: <code>generate/analysis.cppm:267</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function first normalizes the input to well-formed UTF-8 via <code>clore::support::ensure_utf8</code>, then strips any UTF-8 byte order mark using <code>clore::support::strip_utf8_bom</code>. Trailing ASCII whitespace is removed through the internal helper <code>trim_trailing_ascii_whitespace</code>. A presence check via <code>contains_non_whitespace</code> guards against completely blank fragments; if the string is empty or contains only whitespace, the function returns a <code>std::unexpected</code> with a <code>GenerateError</code> that includes the <code>context</code> string. Finally, <code>normalize_analysis_markdown</code> applies additional markdown‑level normalization (for example, trimming spaces inside code spans or normalizing list indentation) before the result is returned.</p><p>The control flow is entirely sequential and error‑oriented: initial encoding and BOM corrections, whitespace trimming, a validity gate that short‑circuits to an error, and a dedicated normalization step. Dependencies are limited to the <code>clore::support</code> string‑utility layer and several file‑local helper functions (<code>trim_trailing_ascii_whitespace</code>, <code>contains_non_whitespace</code>, <code>normalize_analysis_markdown</code>), all defined in the anonymous namespace of the implementation file.</p><h4 id="side-effects-5" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-5" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-5" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-5" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>raw</code> parameter</li><li><code>context</code> parameter</li></ul><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to clean and standardize markdown fragments before embedding in generated documentation.</li></ul><h3 id="clore-generate-parse-markdown-prompt-output" tabindex="-1"><code>clore::generate::parse_markdown_prompt_output</code> <a class="header-anchor" href="#clore-generate-parse-markdown-prompt-output" aria-label="Permalink to &quot;`clore::generate::parse_markdown_prompt_output`&quot;">​</a></h3><p>Declaration: <code>generate/analysis.cppm:24</code></p><p>Definition: <code>generate/analysis.cppm:281</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function <code>parse_markdown_prompt_output</code> is a thin wrapper that delegates all work to <code>normalize_markdown_fragment</code>. It receives the raw markdown prompt output in <code>raw</code> and a <code>context</code> string, then immediately calls <code>normalize_markdown_fragment(raw, context)</code> and returns its result (a <code>std::expected&lt;std::string, GenerateError&gt;</code>). The internal control flow consists solely of this single call; no additional parsing or validation logic is present in the function body. Its only dependency is <code>normalize_markdown_fragment</code>, which performs the actual markdown normalization and is itself part of the anonymous namespace within <code>clore::generate</code>.</p><h4 id="side-effects-6" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-6" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-6" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-6" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>parameter <code>raw</code></li><li>parameter <code>context</code></li></ul><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called to normalize the output of a markdown prompt before further processing</li><li>Used in generation pipeline to clean up raw LLM responses</li></ul><h3 id="clore-generate-parse-structured-response" tabindex="-1"><code>clore::generate::parse_structured_response</code> <a class="header-anchor" href="#clore-generate-parse-structured-response" aria-label="Permalink to &quot;`clore::generate::parse_structured_response`&quot;">​</a></h3><p>Declaration: <code>generate/analysis.cppm:18</code></p><p>Definition: <code>generate/analysis.cppm:252</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function <code>clore::generate::parse_structured_response</code> accepts a raw JSON string (<code>raw</code>) and a human-readable <code>context</code> string (used only for error reporting) and returns a <code>std::expected&lt;T, GenerateError&gt;</code>. Internally it first attempts to deserialize <code>raw</code> into type <code>T</code> via <code>json::from_json</code>; if that fails, it constructs a <code>GenerateError</code> containing a formatted message that includes the <code>context</code> identifier and the parsing error description, then returns an unexpected result. On successful deserialization, the parsed value is moved into a local variable and passed to <code>normalize_analysis</code>, an anonymous‑namespace helper that applies any required post‑processing (such as trimming whitespace or merging partial analyses) before the final value is returned. The function therefore acts as a thin wrapper that combines JSON parsing with a mandatory normalization step, delegating the detailed analysis of the structured response’s content to the external <code>normalize_analysis</code> routine.</p><h4 id="side-effects-7" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-7" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Calls <code>normalize_analysis</code> on the parsed value, which may modify the value or perform other side effects.</li></ul><h4 id="reads-from-7" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-7" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>raw (<code>std::string_view</code>)</li><li>context (<code>std::string_view</code>)</li></ul><h4 id="writes-to-1" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-1" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>The returned <code>std::expected&lt;T, GenerateError&gt;</code> (ownership of the parsed value is transferred)</li><li>The local parsed value before normalization (through <code>normalize_analysis</code>)</li></ul><h4 id="usage-patterns-7" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-7" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Parsing structured JSON responses from AI prompts</li><li>Converting raw generative output into typed analysis objects</li></ul><h3 id="clore-generate-store-fallback-analysis" tabindex="-1"><code>clore::generate::store_fallback_analysis</code> <a class="header-anchor" href="#clore-generate-store-fallback-analysis" aria-label="Permalink to &quot;`clore::generate::store_fallback_analysis`&quot;">​</a></h3><p>Declaration: <code>generate/analysis.cppm:35</code></p><p>Definition: <code>generate/analysis.cppm:335</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function <code>clore::generate::store_fallback_analysis</code> populates a <code>SymbolAnalysisStore</code> with default analysis entries when the primary generation path fails. It accepts a mutable store reference, a constant symbol info object, and a project model. The algorithm first computes a unique key for the symbol via <code>make_symbol_target_key</code>, then dispatches on the symbol’s kind using <code>is_function_kind</code>, <code>is_type_kind</code>, and <code>is_variable_kind</code>. Depending on the kind, it assigns the result of one of three internal fallback generators—<code>fallback_function_analysis</code>, <code>fallback_type_analysis</code>, or <code>fallback_variable_analysis</code>—to the corresponding map within <code>analyses</code>. The function returns <code>void</code> and performs no merging or further processing; it simply inserts a single fallback entry keyed by <code>target_key</code>. All fallback functions are defined in the anonymous namespace of the same translation unit, and the call to <code>make_symbol_target_key</code> is assumed to produce a consistent string key for the symbol.</p><h4 id="side-effects-8" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-8" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Mutates the <code>analyses</code> object by inserting into its <code>functions</code>, <code>types</code>, or <code>variables</code> maps.</li></ul><h4 id="reads-from-8" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-8" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>sym.kind</code></li><li><code>sym</code> (symbol info)</li><li><code>model</code> (project model, only for type fallback)</li></ul><h4 id="writes-to-2" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-2" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li><code>analyses.functions</code></li><li><code>analyses.types</code></li><li><code>analyses.variables</code></li></ul><h4 id="usage-patterns-8" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-8" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called when no real analysis is available to generate placeholder entries.</li><li>Used during initial analysis phase to ensure every symbol has an entry.</li></ul><h3 id="clore-generate-symbol-prompt-kinds-for-symbol" tabindex="-1"><code>clore::generate::symbol_prompt_kinds_for_symbol</code> <a class="header-anchor" href="#clore-generate-symbol-prompt-kinds-for-symbol" aria-label="Permalink to &quot;`clore::generate::symbol_prompt_kinds_for_symbol`&quot;">​</a></h3><p>Declaration: <code>generate/analysis.cppm:29</code></p><p>Definition: <code>generate/analysis.cppm:299</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function determines the base analysis prompt kind for the given symbol by calling <code>analysis_prompt_kind_for_symbol</code>. If no base kind is available, it returns an empty vector. Otherwise, based on the base kind, it returns a sequence of <code>PromptKind</code> values: for <code>FunctionAnalysis</code> it returns <code>FunctionAnalysis</code>, <code>FunctionDeclarationSummary</code>, and <code>FunctionImplementationSummary</code>; for <code>TypeAnalysis</code> it returns <code>TypeAnalysis</code>, <code>TypeDeclarationSummary</code>, and <code>TypeImplementationSummary</code>; for <code>VariableAnalysis</code> it returns only <code>VariableAnalysis</code>; for any other base kind it returns an empty vector. This function effectively maps a single base analysis kind into the complete set of prompt kinds needed for that symbol&#39;s analysis pipeline.</p><h4 id="side-effects-9" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-9" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-9" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-9" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>sym</code> parameter (via <code>analysis_prompt_kind_for_symbol(sym)</code>)</li></ul><h4 id="usage-patterns-9" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-9" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>determining which prompts to generate for a given symbol</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>The <code>generate:analysis</code> module implements the pipeline that converts raw AI‑generated responses into structured analyses for symbols (functions, types, variables). Internal layering proceeds from low‑level utilities (e.g., <code>parse_structured_response</code>, <code>normalize_markdown_fragment</code>) through per‑kind lenient parsers and normalizers (<code>parse_type_analysis_lenient</code>, <code>normalize_analysis</code>) to merging and fallback generators (<code>merge_type_analysis</code>, <code>fallback_type_analysis</code>). The public surface combines these pieces into higher‑level functions such as <code>apply_symbol_analysis_response</code> and <code>build_symbol_analysis_prompt</code>, which orchestrate parsing, normalization, and storage of analysis results, while <code>store_fallback_analysis</code> ensures resilience when primary parsing fails. The module imports foundational types and contexts from <code>generate:model</code> and <code>support</code>, prompts from <code>generate:markdown</code> and <code>generate:evidence</code>, and configuration from <code>config</code> and <code>extract</code>, reflecting a clean separation between analysis logic and the extraction or presentation layers.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../config/">Module config</a></li><li><a href="./../extract/">Module extract</a></li><li><a href="./evidence">Module generate:evidence</a></li><li><a href="./markdown">Module generate:markdown</a></li><li><a href="./model">Module generate:model</a></li><li><a href="./../support/">Module support</a></li></ul>',123))])}const w=n(m,[["render",u]]);export{k as __pageData,w as default};
